def gen(rng, size):
    def build(depth):
        if depth <= 0 or rng.random() < 0.4:
            return rng.choice('01')
        left = build(depth - 1)
        right = build(depth - 1)
        op = rng.choice('&|')
        expr = left + op + right
        if rng.random() < 0.6:
            expr = '(' + expr + ')'
        return expr
    return [build(rng.randint(1, 6))]

