class Solution:
    def minOperationsToFlip(self, expression):
        # Independent: recursive-descent parse into a tree, then DP costs bottom up (iterative parse to avoid recursion).
        # Parse with shunting-yard into postfix, then evaluate cost pairs on a stack.
        # operators &,| equal precedence, left-associative, parens.
        output = []
        ops = []
        prec = {'&': 1, '|': 1}
        for ch in expression:
            if ch in '01':
                output.append(ch)
            elif ch in '&|':
                while ops and ops[-1] != '(' and prec[ops[-1]] >= prec[ch]:
                    output.append(ops.pop())
                ops.append(ch)
            elif ch == '(': 
                ops.append(ch)
            elif ch == ')':
                while ops and ops[-1] != '(':
                    output.append(ops.pop())
                ops.pop()
        while ops:
            output.append(ops.pop())
        INF = float('inf')
        st = []
        for tok in output:
            if tok == '0':
                st.append((0, 1))
            elif tok == '1':
                st.append((1, 0))
            else:
                c0_b, c1_b = st.pop()
                c0_a, c1_a = st.pop()
                # for each desired result and each operator (orig or flipped, +1 if flipped)
                def combine(want):
                    best = INF
                    for opc, oper in ((0, tok), (1, '&' if tok == '|' else '|')):
                        # oper applied to a,b
                        for a in (0, 1):
                            for b in (0, 1):
                                if oper == '&':
                                    res = a & b
                                else:
                                    res = a | b
                                if res == want:
                                    ca = c0_a if a == 0 else c1_a
                                    cb = c0_b if b == 0 else c1_b
                                    best = min(best, opc + ca + cb)
                    return best
                st.append((combine(0), combine(1)))
        c0, c1 = st[0]
        # current value is whichever of c0/c1 is 0; answer is the other (cost to flip)
        return c1 if c0 == 0 else c0

