class Solution:
    def minOperationsToFlip(self, expression):
        INF = float('inf')
        operands = []
        operators = []
        def apply():
            op = operators.pop()
            b0, b1 = operands.pop()
            a0, a1 = operands.pop()
            if op == '&':
                r0 = min(a0 + b0, a0 + b1, a1 + b0)
                r1 = a1 + b1
            else:
                r0 = a0 + b0
                r1 = min(a1 + b1, a1 + b0, a0 + b1)
            # allow flipping this operator at cost 1
            if op == '&':
                f0 = a0 + b0
                f1 = min(a1 + b1, a1 + b0, a0 + b1)
            else:
                f0 = min(a0 + b0, a0 + b1, a1 + b0)
                f1 = a1 + b1
            r0 = min(r0, f0 + 1)
            r1 = min(r1, f1 + 1)
            operands.append((r0, r1))
        for ch in expression:
            if ch == '0':
                operands.append((0, 1))
            elif ch == '1':
                operands.append((1, 0))
            elif ch == '(': 
                operators.append('(')
            elif ch == ')':
                while operators[-1] != '(': 
                    apply()
                operators.pop()
            else:
                while operators and operators[-1] != '(': 
                    apply()
                operators.append(ch)
        while operators:
            apply()
        c0, c1 = operands[0]
        return c1 if c0 == 0 else c0

