var minOperationsToFlip = function(expression) {
    const operands = [];
    const operators = [];
    const apply = () => {
        const op = operators.pop();
        const [b0, b1] = operands.pop();
        const [a0, a1] = operands.pop();
        let r0, r1;
        if (op === '&') {
            r0 = Math.min(a0 + b0, a0 + b1, a1 + b0);
            r1 = a1 + b1;
        } else {
            r0 = a0 + b0;
            r1 = Math.min(a1 + b1, a1 + b0, a0 + b1);
        }
        let f0, f1;
        if (op === '&') {
            f0 = a0 + b0;
            f1 = Math.min(a1 + b1, a1 + b0, a0 + b1);
        } else {
            f0 = Math.min(a0 + b0, a0 + b1, a1 + b0);
            f1 = a1 + b1;
        }
        r0 = Math.min(r0, f0 + 1);
        r1 = Math.min(r1, f1 + 1);
        operands.push([r0, r1]);
    };
    for (const ch of expression) {
        if (ch === '0') operands.push([0, 1]);
        else if (ch === '1') operands.push([1, 0]);
        else if (ch === '(') operators.push('(');
        else if (ch === ')') {
            while (operators[operators.length - 1] !== '(') apply();
            operators.pop();
        } else {
            while (operators.length && operators[operators.length - 1] !== '(') apply();
            operators.push(ch);
        }
    }
    while (operators.length) apply();
    const [c0, c1] = operands[0];
    return c0 === 0 ? c1 : c0;
};
